// 교육용 빅뱅 시뮬레이션 - 원자핵 모델 기반 4단계 진화 과정
import * as THREE from "three";

/**
 * 1️⃣ 쿼크-글루온 플라즈마 (2초)
 * 중앙의 핵 + 주변 입자들이 빠르게 회전하며 접근
 */
export function createQuarkGluonPlasma(numParticles = 500000) {
  const group = new THREE.Group();

  // 중앙 핵 (50만 개의 고에너지 입자)
  const coreGeometry = new THREE.BufferGeometry();
  const numCore = 50000;
  const corePositions = new Float32Array(numCore * 3);
  const coreColors = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    const r = Math.random() * 80;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 극도로 뜨거운 상태: 흰색/노란색
    if (Math.random() > 0.5) {
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 1.0;
    } else {
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 0.9;
      coreColors[i * 3 + 2] = 0.2;
    }
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 1.0,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.9
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  group.add(corePoints);

  // 주변 입자들 (400,000개) - 원형 궤도
  const orbitGeometry = new THREE.BufferGeometry();
  const numOrbit = 400000;
  const orbitPositions = new Float32Array(numOrbit * 3);
  const orbitColors = new Float32Array(numOrbit * 3);
  const orbitAngles = new Float32Array(numOrbit); // 각도 저장

  for (let i = 0; i < numOrbit; i++) {
    // 여러 궤도 레이어 생성
    const layer = Math.floor(i / (numOrbit / 3)); // 0, 1, 2
    const orbitRadius = 150 + layer * 120;

    const angle = Math.random() * Math.PI * 2;
    const orbitalTilt = Math.random() * Math.PI * 0.3;

    orbitPositions[i * 3] = Math.cos(angle) * orbitRadius * Math.cos(orbitalTilt);
    orbitPositions[i * 3 + 1] = Math.sin(angle) * orbitRadius;
    orbitPositions[i * 3 + 2] = Math.sin(angle) * orbitRadius * Math.sin(orbitalTilt);

    orbitAngles[i] = angle;

    // 쿼크 색상
    const type = Math.random();
    if (type < 0.3) {
      orbitColors[i * 3] = 1.0; // 빨강
      orbitColors[i * 3 + 1] = 0.2;
      orbitColors[i * 3 + 2] = 0.2;
    } else if (type < 0.6) {
      orbitColors[i * 3] = 0.2; // 초록
      orbitColors[i * 3 + 1] = 1.0;
      orbitColors[i * 3 + 2] = 0.2;
    } else if (type < 0.85) {
      orbitColors[i * 3] = 0.2; // 파랑
      orbitColors[i * 3 + 1] = 0.2;
      orbitColors[i * 3 + 2] = 1.0;
    } else {
      orbitColors[i * 3] = 1.0; // 노랑
      orbitColors[i * 3 + 1] = 1.0;
      orbitColors[i * 3 + 2] = 0.2;
    }
  }

  orbitGeometry.setAttribute("position", new THREE.BufferAttribute(orbitPositions, 3));
  orbitGeometry.setAttribute("color", new THREE.BufferAttribute(orbitColors, 3));

  const orbitMaterial = new THREE.PointsMaterial({
    size: 0.8,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.7
  });

  const orbitPoints = new THREE.Points(orbitGeometry, orbitMaterial);
  orbitPoints.userData.orbitAngles = orbitAngles;
  orbitPoints.userData.numOrbit = numOrbit;
  group.add(orbitPoints);

  return { group, orbitPoints };
}

/**
 * 2️⃣ 쿼크 결합 → 양성자/중성자 (2.5초)
 * 중앙 핵 + 3개 쿼크가 모여드는 궤도들
 */
export function createQuarkCombination(stageProgress) {
  const group = new THREE.Group();

  // 중앙 핵 (양성자/중성자 형성)
  const coreGeometry = new THREE.BufferGeometry();
  const numCore = 100000;
  const corePositions = new Float32Array(numCore * 3);
  const coreColors = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    const r = Math.random() * 60 * stageProgress;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 양성자/중성자
    if (Math.random() > 0.5) {
      coreColors[i * 3] = 1.0; // 빨강 (양성자)
      coreColors[i * 3 + 1] = 0.1;
      coreColors[i * 3 + 2] = 0.1;
    } else {
      coreColors[i * 3] = 0.1; // 파랑 (중성자)
      coreColors[i * 3 + 1] = 0.1;
      coreColors[i * 3 + 2] = 1.0;
    }
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 1.5 + stageProgress * 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.5 + stageProgress * 0.5
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  group.add(corePoints);

  // 3개의 쿼크 궤도 (3개 원형 레이어)
  const orbitsData = [
    { radius: 200, color: [1.0, 0.2, 0.2], count: 30000 }, // 빨강
    { radius: 280, color: [0.2, 1.0, 0.2], count: 40000 }, // 초록
    { radius: 360, color: [0.2, 0.2, 1.0], count: 30000 }  // 파랑
  ];

  orbitsData.forEach((orbit, idx) => {
    const orbitGeom = new THREE.BufferGeometry();
    const positions = new Float32Array(orbit.count * 3);
    const colors = new Float32Array(orbit.count * 3);

    // 진행에 따라 반지름 감소
    const currentRadius = orbit.radius * (1 - stageProgress) + 120 * stageProgress;

    for (let i = 0; i < orbit.count; i++) {
      const angle = (i / orbit.count) * Math.PI * 2 + Math.random() * 0.2;
      const orbitalTilt = Math.random() * Math.PI * 0.2;

      positions[i * 3] = Math.cos(angle) * currentRadius * Math.cos(orbitalTilt);
      positions[i * 3 + 1] = Math.sin(angle) * currentRadius;
      positions[i * 3 + 2] = Math.sin(angle) * currentRadius * Math.sin(orbitalTilt);

      colors[i * 3] = orbit.color[0];
      colors[i * 3 + 1] = orbit.color[1];
      colors[i * 3 + 2] = orbit.color[2];
    }

    orbitGeom.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    orbitGeom.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    const orbitMat = new THREE.PointsMaterial({
      size: 1.0,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 1 - stageProgress * 0.4
    });

    const orbitPoints = new THREE.Points(orbitGeom, orbitMat);
    group.add(orbitPoints);
  });

  return group;
}

/**
 * 3️⃣ 핵융합 → 원자핵 형성 (2.5초)
 * 중앙 핵 + 원소별 다층 궤도 (He, Li, Be)
 */
export function createNucleosynthesis(stageProgress) {
  const group = new THREE.Group();

  // 중앙 핵 (원자핵 형성)
  const coreGeometry = new THREE.BufferGeometry();
  const numCore = 150000;
  const corePositions = new Float32Array(numCore * 3);
  const coreColors = new Float32Array(numCore * 3);

  for (let i = 0; i < numCore; i++) {
    const r = Math.random() * 100 * stageProgress;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 핵의 종류
    const nucleusType = i % 3;
    if (nucleusType === 0) {
      // 헬륨-4: 시안
      coreColors[i * 3] = 0.2;
      coreColors[i * 3 + 1] = 0.8 + stageProgress * 0.2;
      coreColors[i * 3 + 2] = 1.0;
    } else if (nucleusType === 1) {
      // 리튬: 초록
      coreColors[i * 3] = 0.2;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 0.2;
    } else {
      // 베릴륨: 노랑
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 0.9;
      coreColors[i * 3 + 2] = 0.2;
    }
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 2.0 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.5 + stageProgress * 0.5
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  group.add(corePoints);

  // 4개의 양성자/중성자 궤도
  const orbitRadii = [180, 280, 380, 480];
  const orbitColors = [
    [1.0, 0.2, 0.2], // 빨강
    [0.2, 1.0, 0.2], // 초록
    [0.2, 0.2, 1.0], // 파랑
    [1.0, 1.0, 0.2]  // 노랑
  ];

  orbitRadii.forEach((baseRadius, idx) => {
    const orbitGeom = new THREE.BufferGeometry();
    const count = 40000;
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);

    // 진행에 따라 반지름 감소
    const currentRadius = baseRadius * (1 - stageProgress) + 140 * stageProgress;

    for (let i = 0; i < count; i++) {
      const angle = (i / count) * Math.PI * 2 + Math.random() * 0.2;
      const orbitalTilt = Math.random() * Math.PI * 0.2;

      positions[i * 3] = Math.cos(angle) * currentRadius * Math.cos(orbitalTilt);
      positions[i * 3 + 1] = Math.sin(angle) * currentRadius;
      positions[i * 3 + 2] = Math.sin(angle) * currentRadius * Math.sin(orbitalTilt);

      colors[i * 3] = orbitColors[idx % 4][0];
      colors[i * 3 + 1] = orbitColors[idx % 4][1];
      colors[i * 3 + 2] = orbitColors[idx % 4][2];
    }

    orbitGeom.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    orbitGeom.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    const orbitMat = new THREE.PointsMaterial({
      size: 1.2,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 1 - stageProgress * 0.3
    });

    const orbitPoints = new THREE.Points(orbitGeom, orbitMat);
    group.add(orbitPoints);
  });

  return group;
}

/**
 * 4️⃣ 원자 형성 (3초)
 * 중앙 핵 + 다층 전자 궤도 (원자 모델)
 */
export function createAtomFormation(stageProgress) {
  const group = new THREE.Group();

  // 중앙 핵 (많은 수의 원자)
  const coreGeometry = new THREE.BufferGeometry();
  const numAtoms = 100000;
  const corePositions = new Float32Array(numAtoms * 3);
  const coreColors = new Float32Array(numAtoms * 3);

  for (let i = 0; i < numAtoms; i++) {
    const r = Math.random() * 5;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;

    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 핵: 노란색
    coreColors[i * 3] = 1.0;
    coreColors[i * 3 + 1] = 0.8;
    coreColors[i * 3 + 2] = 0.1;
  }

  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));

  const coreMaterial = new THREE.PointsMaterial({
    size: 4 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true
  });

  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  group.add(corePoints);

  // 3개의 전자 궤도 (K, L, M shell)
  const electronOrbits = [
    { radius: 100, count: 150000, color: [0.2, 0.8, 1.0] }, // K shell (2e)
    { radius: 200, count: 150000, color: [0.5, 0.9, 1.0] }, // L shell (8e)
    { radius: 300, count: 100000, color: [0.7, 0.95, 1.0] }  // M shell
  ];

  electronOrbits.forEach((orbit, shellIdx) => {
    const electronGeom = new THREE.BufferGeometry();
    const positions = new Float32Array(orbit.count * 3);
    const colors = new Float32Array(orbit.count * 3);

    for (let i = 0; i < orbit.count; i++) {
      const time = Date.now() * 0.001;
      const angle = (i / orbit.count) * Math.PI * 2 + time * (shellIdx + 1) * 0.5;
      const orbitalTilt = (i / orbit.count) * Math.PI * 0.4;

      // 진행도에 따라 궤도 반지름 증가
      const currentRadius = orbit.radius * stageProgress;

      positions[i * 3] = Math.cos(angle) * currentRadius * Math.cos(orbitalTilt);
      positions[i * 3 + 1] = Math.sin(angle) * currentRadius;
      positions[i * 3 + 2] = Math.sin(angle) * currentRadius * Math.sin(orbitalTilt);

      colors[i * 3] = orbit.color[0];
      colors[i * 3 + 1] = orbit.color[1];
      colors[i * 3 + 2] = orbit.color[2];
    }

    electronGeom.setAttribute("position", new THREE.BufferAttribute(positions, 3));
    electronGeom.setAttribute("color", new THREE.BufferAttribute(colors, 3));

    const electronMat = new THREE.PointsMaterial({
      size: 1.5 + stageProgress * 1,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.2 + stageProgress * 0.6
    });

    const electronPoints = new THREE.Points(electronGeom, electronMat);
    electronPoints.userData.isAnimated = true;
    electronPoints.userData.shellIndex = shellIdx;
    group.add(electronPoints);
  });

  return group;
}



/**
 * 빅뱅 교육용 단계 정보
 */
export const educationalBigBangStages = [
  {
    id: 0,
    name: "쿼크-글루온 플라즈마",
    timeRange: "10⁻¹² 초 (1 피코초)",
    koreanTime: "우주 1조분의 1초",
    description: "우주가 극도로 뜨거워 쿼크와 글루온이 자유롭게 움직이고 있습니다. 이들은 아직 결합되지 않은 상태입니다.",
    color: 0xff6b6b,
    duration: 2000
  },
  {
    id: 1,
    name: "쿼크 결합 → 양성자/중성자",
    timeRange: "10⁻⁶ 초 (1 마이크로초)",
    koreanTime: "우주 100만분의 1초",
    description: "온도가 낮아지면서 쿼크 3개가 결합하여 양성자와 중성자가 형성됩니다. 강한 핵력에 의해 결합됩니다.",
    color: 0x4ecdc4,
    duration: 2500
  },
  {
    id: 2,
    name: "핵융합 → 원자핵 형성",
    timeRange: "1-3 분",
    koreanTime: "우주 처음 3분",
    description: "양성자와 중성자가 결합하여 헬륨-4, 리튬 등 가벼운 원소의 핵이 형성됩니다. 이를 빅뱅 핵합성이라고 합니다.",
    color: 0x95e77d,
    duration: 2500
  },
  {
    id: 3,
    name: "원자 형성",
    timeRange: "38만 년",
    koreanTime: "우주 38만 년",
    description: "우주가 충분히 식으면서 전자가 핵 주위를 돌기 시작합니다. 중성 원자(수소, 헬륨)가 형성되고 우주가 투명해집니다.",
    color: 0xb0a0ff,
    duration: 3000
  }
];

export function getEducationalStageInfo(stageId) {
  return educationalBigBangStages[stageId];
}

export function getTotalEducationalBigBangDuration() {
  return educationalBigBangStages.reduce((sum, stage) => sum + stage.duration, 0);
}
